import{bV as s,aL as a,u as p,G as o}from"./chunks/framework.BQalybiP.js";const c=JSON.parse('{"title":"Level1 - Office and school","description":"","frontmatter":{"date":"2026-05-06T14:46:28.000Z","title":"Level1 - Office and school","categories":["英语","Speaking"]},"headers":[],"relativePath":"06.英语/Speaking/02.Level1 - Office and school.md","filePath":"06.英语/Speaking/02.Level1 - Office and school.md"}'),t={name:"06.英语/Speaking/02.Level1 - Office and school.md"};function i(r,e,n,l,h,f){return a(),p("div",null,[...e[0]||(e[0]=[o('<h1 id="level1-office-and-school" tabindex="-1">Level1 - Office and school <a class="header-anchor" href="#level1-office-and-school" aria-label="Permalink to &quot;Level1 - Office and school&quot;">​</a></h1><h3 id="询问他人意见" tabindex="-1">询问他人意见 <a class="header-anchor" href="#询问他人意见" aria-label="Permalink to &quot;询问他人意见&quot;">​</a></h3><p>通常可以使用 How 来询问他人意见。</p><p>比如：How&#39;s your teacher?</p><p>How are your teachers?</p><p><strong>Positive response:</strong></p><p>They&#39;re good.</p><p>She&#39;s great.</p><p><strong>Neutral response:</strong></p><p>He&#39;s OK.</p><p>They&#39;re so-so.</p><p><strong>Negative response:</strong></p><p>He&#39;s bad.</p><p>They&#39;re terrible.</p><h3 id="介绍人或物" tabindex="-1">介绍人或物 <a class="header-anchor" href="#介绍人或物" aria-label="Permalink to &quot;介绍人或物&quot;">​</a></h3><p>可以使用 This is 或者 That is</p><p>This is my desk. / 否定：This is not my desk.</p><p>That is John. / 否定：That is not John.</p><p>this 用来指代离的比较近的人或物，that 用来指代离的比较远的人或物。</p><p>将 is 放在句首可以变成一般疑问句用于询问。</p><p>Is this your desk?</p><p>Yes, it is. / No, it isn&#39;t.</p><h3 id="询问某人的年龄" tabindex="-1">询问某人的年龄 <a class="header-anchor" href="#询问某人的年龄" aria-label="Permalink to &quot;询问某人的年龄&quot;">​</a></h3><p>How old are you?</p><p>How old is she / he?</p><p>回答的时候可以只给出数字，也可以在后面加上 years old</p><p><strong>英文文化：</strong> 在英文国家，询问某人的年龄被认为是粗鲁的。</p><h3 id="课堂笔记" tabindex="-1">课堂笔记： <a class="header-anchor" href="#课堂笔记" aria-label="Permalink to &quot;课堂笔记：&quot;">​</a></h3><p><strong>自我介绍环节中：</strong></p><p>提到希望可以与国外的朋友流利的用英文交流，可以用英文思维进行回答。</p><p>I want to speak English well.</p><p>I want to speak with foreigners.</p><p><strong>词汇扩展：</strong></p><p>mailbox 邮箱</p><p>poster 海报</p><p>banner 横幅</p><p>calculate 计算 / calendar 日历</p><p>front desk 前台</p><p><strong>口语交流（Part 1）：</strong></p><p>Lily is Paul&#39;s daughter. / Lily is Paul&#39;s little girl. （国外形容女儿更倾向于使用 little girl）</p><p>儿子可以使用 little boy 代替 son，口语当中。</p><p>Paul is Lily&#39;s father/dad/papa/daddy.</p><p>Joe looks like Paul&#39;s father.</p><p>looks like：长得像，可能是某个人长得像另一个人。</p><p>如果想准确表述看起来像，可以使用：Joe seems like Paul&#39;s father.</p><p>I think Musa is Joe&#39;s father.</p><p>不确定的时候，口语也可以说：I guess Musa is Joe&#39;s father. （更多表达不确定，而不是我猜）</p><p>My guess is that Musa is Joe&#39;s father.</p><p>Joe is 55 years old.</p><p>年龄是猜测的，并不是实际知道了解的时候，可以表述为：Joe is</p><p>about/around 50/55 years old.</p><p>Joe is in his fifties. 他处于50多岁。</p><p>Joe is in his early fifties. / Joe is in his mid-fifties. / Joe is in his late fifties.</p><p>I guess Paul is 32 years old.</p><p>I guess Paul is in his early thirties.</p><p>Lily seems like a 7-year-old.</p><p>Lily seems 7 years old.</p><p>Lily seems like she is 7 (years old).</p><p>I think Musa is younger than Joe, I guess he is 46 years old.</p><p>She is one/a year older than me.</p><p>I guess he was born in 1970s. 我猜想他出生于70年代。</p><p>I believe he was born in 1975. believe 是确信，语义更为强烈。</p><p><strong>consider means think about carefully</strong></p><p><strong>口语交流（Part 2）：</strong></p><p>Q: Thanks for showing me the office.</p><p>A: You&#39;re welcome. / My pleasure. / It&#39;s my pleasure. / It&#39;s my honor. / I&#39;m happy to help.</p><p>Q: It such a big office.</p><p>A: Yeah, that&#39;s a very big one. / Yeah, let me introduce the office. / Yeah, we have many desks and computers here. / Yeah, it&#39;s quite a large.</p><p>There is an elevator over here.</p><p>仅仅只有一台：Yes, just one. / Yes, only one.</p><p>There are some restrooms in different places.</p><p>It&#39;s near the manager&#39;s office.</p><p>It&#39;s close to the manager&#39;s office.</p><p>可以使用问题中的某些词语。</p><p>It&#39;s behind of the manager&#39;s office. / The manager&#39;s office is in front of the restroom.</p><p>如果未听清需要重复，可以使用</p><p>Sorry please say it again.</p><p>Excuse me?</p><p>Pardon?</p><p>There are many new coffee cups prepared for you in the kitchen.</p><p>Prepare for 用于老板什么的，会表现的比较生疏</p><p>You can use the new coffee cups over there.</p><p>and so on. and things like that 等等，诸如此类。</p>',83)])])}const u=s(t,[["render",i]]);export{c as __pageData,u as default};
